import datetime
from datetime import datetime

start_date = datetime.now().isoformat()
entries = [
    {"description": "Warm-up", "progress": 10},
    {"description": "Sprints", "progress": 40},
    {"description": "Cool-down", "progress": 20},
]

json_obj = {"name": "My Workout Plan", "start_date": start_date, "entries": entries}

print(json.dumps(json_obj, indent=4, sort_keys=True))
```

