function generate(question) {
  const labels = ["test", "another test", "a third test"];
  const scores = [6, 7, 8, 9, 10];

  return {
    label: question.label,
    scores: labels.map(label => scores[Math.floor(Math.random() * scores.length)])
  };
}
```

