          "expires_at": {
            "type": "string",
            "description": "Expires at timestamp"
          },
          "refresh_token": {
            "type": "string",
            "description": "Refresh token"
          }
        }
      },
      "ErrorResponse": {
        "type": "object",
        "properties": {
          "error": {
            "type": "string",
            "description": "Error message"
          }
        }
      }
    }
  }
}
