            "description": "OK",
            "schema": {
              "$ref": "#/components/schemas/LoginResponse"
            }
          }
        }
      }
    },
    "/logout": {
      "get": {
        "consumes": [
          "application/json"
        ],
        "produces": [
          "application/json"
        ],
        "tags": [
          "authentication"
        ],
        "summary": "Log out user",
        "description": "API endpoint for logging out a user",
        "responses": {
          "204": {
            "description": "No Content"
          }
        }
      }
    }
  },
  "components": {
    "schemas": {
      "LoginRequest": {
        "type": "object",
        "properties": {
          "email": {
            "type": "string",
            "format": "email"
          },
          "password": {
            "type": "string",
            "minLength": 8
          }
        }
      },
      "LoginResponse": {
        "type": "object",
        "properties": {
          "token": {
            "type": "string"
          }
        }
      },
      "LoginResponse": {
        "type": "object",
        "properties": {
          "token": {
            "type": "string"
          }
        }
      }
    }
  }
}
```

Explanation:
- `openapi` is the name of the OpenAPI spec file (version 3.0.0)
- `info` is the information about the API, including version, title, and description
- `paths` is the paths defined for the API, including `/login` and `/logout`
- `components` is the schemas used for the API, including the LoginRequest and LoginResponse schema
- `responses` is the responses for the API, including `200` and `204` status codes
- `tags` are the tags used to categorize the API
- `summary` is the API summary
- `description` is the API description

